#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int a = 0, b = 0;
        for (int i = 0; i < n; i++) {
            char s[3];
            scanf("%s", s);
            if (s[0] == 'a') a++;
            else b++;
            if (strlen(s) == 2) {
                if (s[1] == 'a') a++;
                else b++;
            }
        }
        int ans = a + b;
        if (a > b) ans = 2 * b + (a - b);
        else ans = 2 * a + (b - a);
        printf("%d\n", ans);
    }
    return 0;
}

