import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int a = 0, b = 0;
            for (int i = 0; i < n; i++) {
                String s = sc.next();
                if (s.charAt(0) == 'a') a++;
                else b++;
                if (s.length() == 2) {
                    if (s.charAt(1) == 'a') a++;
                    else b++;
                }
            }
            int ans = a + b;
            if (a > b) ans = 2 * b + (a - b);
            else ans = 2 * a + (b - a);
            System.out.println(ans);
        }
    }
}

